SECRET_KEY = "REPLACE_WITH_A_SECURE_RANDOM_KEY"
ALGORITHM = "HS256"


def generate_jwt(user_id: str, role: str, expires_in: int = 3600) -> str:
    """
    Returns a signed JWT containing the user's ID and role.
    expires_in is expressed in seconds (default: 1 hour).
    """
    now = int(time.time())
    payload = {
        "sub": user_id,          # subject (user identifier)
        "role": role,            # custom claim
        "iat": now,              # issued-at timestamp
        "exp": now + expires_in  # expiration timestamp
    }
    return jwt.encode(payload, SECRET_KEY, algorithm=ALGORITHM)


def verify_jwt(token: str) -> Optional[dict]:
    """
    Verifies signature & expiration, returning the decoded payload
    or None if the token is invalid/expired.
    """
    try:
        return jwt.decode(token, SECRET_KEY, algorithms=[ALGORITHM])
    except jwt.PyJWTError:
        return None


